<!DOCTYPE html><html lang="en"><head><title>Customer Inquiry</title><style>body{font-family:sans-serif;background:#1a1a2e;color:#eee;padding:2rem}table{width:100%;border-collapse:collapse;background:#16213e}th{background:#0f3460;padding:.75rem;text-align:left}td{padding:.75rem;border-bottom:1px solid #333}.search{margin-bottom:1rem}.search input{padding:.5rem;width:300px;background:#16213e;border:1px solid #0f3460;color:#eee;border-radius:4px}.badge{padding:.25rem .5rem;border-radius:4px;font-size:.85rem}.badge-active{background:#00b894;color:#fff}.badge-inactive{background:#d63031;color:#fff}</style></head><body><h1>🔍 Customer Inquiry</h1><div class="search"><input type="text" placeholder="Search by name..." id="searchInput"><button onclick="search()">Search</button></div><table><thead><tr><th>Customer #</th><th>Name</th><th>Balance</th><th>Status</th></tr></thead><tbody id="results"></tbody></table><script>function search(){const name=document.getElementById('searchInput').value;fetch('/api/inquiry?search='+encodeURIComponent(name)).then(r=>r.json()).then(data=>{const tbody=document.getElementById('results');tbody.innerHTML='';data.data.forEach(c=>{const row=tbody.insertRow();row.innerHTML=`<td>${c.id}</td><td>${c.name}</td><td>$${c.balance}</td><td><span class="badge badge-active">Active</span></td>`})})}</script></body></html>